import{_ as e,o as r,c as a,a2 as d}from"./chunks/framework.c3r8iWL8.js";const u=JSON.parse('{"title":"Guide: Runtime on AWS","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/runtime-aws.md","filePath":"guides/runtime-aws.md","lastUpdated":1782929962000}'),o={name:"guides/runtime-aws.md"};function n(s,t,i,l,h,c){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="guide-runtime-on-aws" tabindex="-1">Guide: Runtime on AWS <a class="header-anchor" href="#guide-runtime-on-aws" aria-label="Permalink to &quot;Guide: Runtime on AWS&quot;">​</a></h1><p><strong>Decision:</strong> Where application workloads run and how they&#39;re exposed.</p><p>Related: <a href="./../ARCHITECTURE.html">ARCHITECTURE.md</a> · <a href="./identity-access-secrets.html">identity-access-secrets.md</a></p><hr><h2 id="compute" tabindex="-1">Compute <a class="header-anchor" href="#compute" aria-label="Permalink to &quot;Compute&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>ECS Fargate</strong></td><td>No cluster nodes to manage; good default</td><td>Less K8s ecosystem</td></tr><tr><td><strong>EKS</strong></td><td>Portable K8s; rich ecosystem</td><td>Operational overhead; cost</td></tr><tr><td><strong>Lambda</strong></td><td>Pay per use; great for event/API thin layers</td><td>Cold start; duration limits</td></tr><tr><td><strong>EC2 (self-managed)</strong></td><td>Full control</td><td><strong>Pitfall:</strong> you operate the fleet</td></tr><tr><td><strong>App Runner</strong></td><td>Simple container deploy</td><td>Less control for complex networking</td></tr></tbody></table><p><strong>Recommended:</strong> Fargate for most services; Lambda for event-driven and low-traffic APIs; EKS only when K8s is org mandate.</p><hr><h2 id="api-exposure" tabindex="-1">API exposure <a class="header-anchor" href="#api-exposure" aria-label="Permalink to &quot;API exposure&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>ALB + ECS</strong></td><td>Flexible; WebSockets</td><td>You manage routing rules</td></tr><tr><td><strong>API Gateway + Lambda</strong></td><td>Throttling, auth built-in</td><td>Cost at high RPS</td></tr><tr><td><strong>API Gateway + VPC Link + ALB</strong></td><td>Central auth + container backend</td><td>Complexity</td></tr><tr><td><strong>CloudFront + WAF front</strong></td><td>Edge caching and protection</td><td>Cache invalidation discipline</td></tr></tbody></table><hr><h2 id="data-stores-common-patterns" tabindex="-1">Data stores (common patterns) <a class="header-anchor" href="#data-stores-common-patterns" aria-label="Permalink to &quot;Data stores (common patterns)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Need</th><th>Options</th><th>Pitfall</th></tr></thead><tbody><tr><td>Relational</td><td>RDS Aurora, RDS PostgreSQL</td><td>Publicly accessible RDS</td></tr><tr><td>Key-value / scale</td><td>DynamoDB</td><td>Wrong access patterns → cost</td></tr><tr><td>Cache</td><td>ElastiCache Redis</td><td>Cache as source of truth</td></tr><tr><td>Object</td><td>S3</td><td>Public bucket ACLs</td></tr><tr><td>Search (app)</td><td>OpenSearch</td><td>Confusing with ADR index — separate domains</td></tr></tbody></table><hr><h2 id="ai-services-on-aws" tabindex="-1">AI services on AWS <a class="header-anchor" href="#ai-services-on-aws" aria-label="Permalink to &quot;AI services on AWS&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Use</th><th>Pitfall</th></tr></thead><tbody><tr><td><strong>Bedrock</strong></td><td>Agents, batch, planning</td><td>Ungoverned model access per team</td></tr><tr><td><strong>Amazon Q</strong></td><td>Developer AWS assist</td><td>Not a runtime for customer-facing AI</td></tr><tr><td><strong>SageMaker</strong></td><td>Custom models</td><td>Overkill for codegen assist</td></tr></tbody></table><p>Keep <strong>customer-facing AI</strong> architecture in ADRs separate from <strong>developer tooling AI</strong>.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>EKS by default</strong></td><td>Cost and complexity without need</td><td>ADR required for EKS</td></tr><tr><td><strong>Lambda for everything</strong></td><td>15-min limit; debugging pain</td><td>Domain-driven split</td></tr><tr><td><strong>Hardcoded credentials</strong></td><td>AI generates <code>AKIA...</code> in samples</td><td>Secrets Manager + lint — see <a href="./identity-access-secrets.html">Identity guide</a></td></tr><tr><td><strong>Single AZ</strong></td><td>AZ outage = outage</td><td>Multi-AZ ADR for T1</td></tr><tr><td><strong>No WAF on public APIs</strong></td><td>OWASP exposure</td><td>WAF + rate limits</td></tr><tr><td><strong>AI suggests wrong service</strong></td><td>e.g. self-hosted Kafka vs EventBridge</td><td>ADR corpus + Q guardrails</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>VPC → private subnets → ECS Fargate behind ALB → RDS/DynamoDB as fit → API Gateway where edge auth needed → Bedrock via VPC endpoint for internal agents.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./ci-cd-release.html">CI/CD &amp; release</a> · <a href="./observability-monitoring-qa.html">Observability</a></li></ul>',26)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
